import{_ as t}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{o as a,c as o,af as r}from"./chunks/runtime-core.esm-bundler.p2kBHoTO.js";const h=JSON.parse('{"title":"Безоблачные инструменты","description":"Семь приложений в браузере без облака. IDEF0-редактор, зашифрованный дневник, MIDI-тренажёр, OpenPose, планировщик, журнал решений, WebGPU-визуализатор.","frontmatter":{"title":"Безоблачные инструменты","date":"2026-06-11T00:00:00.000Z","description":"Семь приложений в браузере без облака. IDEF0-редактор, зашифрованный дневник, MIDI-тренажёр, OpenPose, планировщик, журнал решений, WebGPU-визуализатор.","head":[["link",{"rel":"canonical","href":"https://alterfo.github.io/posts/2026-06-11-instrumenty-v-brauzere-bez-oblaka"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Безоблачные инструменты"}],["meta",{"property":"og:description","content":"Семь приложений в браузере без облака. IDEF0-редактор, зашифрованный дневник, MIDI-тренажёр, OpenPose, планировщик, журнал решений, WebGPU-визуализатор."}],["meta",{"property":"og:url","content":"https://alterfo.github.io/posts/2026-06-11-instrumenty-v-brauzere-bez-oblaka"}],["meta",{"property":"og:image","content":"https://alterfo.github.io/og.png"}],["meta",{"property":"og:site_name","content":"Alterfo"}],["meta",{"property":"og:locale","content":"ru_RU"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Безоблачные инструменты"}],["meta",{"name":"twitter:description","content":"Семь приложений в браузере без облака. IDEF0-редактор, зашифрованный дневник, MIDI-тренажёр, OpenPose, планировщик, журнал решений, WebGPU-визуализатор."}],["meta",{"name":"twitter:image","content":"https://alterfo.github.io/og.png"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BlogPosting\\",\\"headline\\":\\"Безоблачные инструменты\\",\\"description\\":\\"Семь приложений в браузере без облака. IDEF0-редактор, зашифрованный дневник, MIDI-тренажёр, OpenPose, планировщик, журнал решений, WebGPU-визуализатор.\\",\\"url\\":\\"https://alterfo.github.io/posts/2026-06-11-instrumenty-v-brauzere-bez-oblaka\\",\\"inLanguage\\":\\"ru-RU\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Oleg Sidorkin\\",\\"alternateName\\":\\"alterfo\\",\\"url\\":\\"https://alterfo.github.io\\",\\"jobTitle\\":\\"Software Engineer\\",\\"knowsAbout\\":[\\"Music\\",\\"Audio DSP\\",\\"AI\\",\\"RAG\\",\\"Frontend Development\\",\\"Solution Architecture\\"],\\"sameAs\\":[\\"https://github.com/alterfo\\"]},\\"datePublished\\":\\"2026-06-11\\"}"]]},"headers":[],"relativePath":"posts/2026-06-11-instrumenty-v-brauzere-bez-oblaka.md","filePath":"posts/2026-06-11-instrumenty-v-brauzere-bez-oblaka.md"}'),s={name:"posts/2026-06-11-instrumenty-v-brauzere-bez-oblaka.md"};function i(n,e,p,l,m,u){return a(),o("div",null,[...e[0]||(e[0]=[r('<p>Запись в Notion - и текст на чужом сервере. Задачи в облачном планировщике - данные в чужой аналитике.</p><p>Волна локальных LLM показала широкой аудитории, что on-device - это реально. Модель работает, данные не покидают машину. Тот же сдвиг происходит с обычными инструментами. Всё заметнее, что ежемесячная подписка - это аренда софта, которым не владеешь и который нельзя отключить от сети.</p><p>Я доделал свои 7 pet-проектов. Все работают целиком в браузере, без сервера, без регистрации, без отправки данных куда-либо. Только локальное хранилище, шифрование на стороне клиента и нативные браузерные API. Идея &quot;колеса жизни&quot;, вокруг которого они собраны, описана в посте <a href="/posts/2020-09-04-canvas-circle-of-life.html">Круг жизни</a>; тогда это была визуализация верхнеуровневая, на главной странице сайта я визуализировал степень готовности каждого инструмента.</p><h2 id="idef0-редактор-для-функциональных-диаграмм" tabindex="-1">IDEF0-редактор для функциональных диаграмм <a class="header-anchor" href="#idef0-редактор-для-функциональных-диаграмм" aria-label="Permalink to &quot;IDEF0-редактор для функциональных диаграмм&quot;">​</a></h2><p>IDEF0 - простейший стандарт описания бизнес-процессов, разработанный в ВМФ США для описания производства. Им легко описывать любые бизнес-процессы верхнеуровнево. Для более детальной проработки - BPMN подойдет лучше. Когда компания рисует схему &quot;как мы обрабатываем заявки&quot; или &quot;как устроена цепочка согласований&quot; - это внутренняя кухня, которую не хочется отправлять в чужое облако. При этом специализированного браузерного редактора IDEF0 до сих пор не было вообще. Стандарт нишевой, и в универсальных рисовалках он превращается в набор прямоугольников без стандартизации.</p><p>Редактор знает правила стандарта и проверяет диаграмму на лету. Неправильно подключённая стрелка подсвечивается прямо на схеме, как ошибка компилятора. Крупный блок можно &quot;провалить&quot; вглубь и расписать подробнее, так строится иерархия процессов. Готовая диаграмма выгружается в SVG, PNG или JSON.</p><details class="details custom-block"><summary>Под капотом</summary><p>SVG + Vue 3, строго по американскому федеральному стандарту FIPS 183. Валидация ICOM-правил даёт каждой стрелке строгую семантику. Вход слева, управление сверху, выход справа, механизм снизу. Данные хранятся в IndexedDB браузера, открытые вкладки синхронизируются между собой через localStorage.</p></details><p>→ <a href="/idef0.html">IDEF0-редактор</a> | <a href="/projects/idef0-editor.html">Разбор архитектуры</a></p><h2 id="зашифрованныи-дневник-в-браузере" tabindex="-1">Зашифрованный дневник в браузере <a class="header-anchor" href="#зашифрованныи-дневник-в-браузере" aria-label="Permalink to &quot;Зашифрованный дневник в браузере&quot;">​</a></h2><p>Большинство дневниковых приложений хранят записи в облаке разработчика и берут за это деньги. Day One синхронизирует через свои серверы, Notion индексирует всё, что в него попадает. Для текста, который пишется только для себя, это странная архитектура.</p><p>Этот дневник открывается паролем и мотивирует писать 500 слов в день, счётчик прогресса ведётся сам. Прошлые записи доступны в том же интерфейсе. Переносить между девайсами можно с помощью функций Импорт/Экспорт, наружу уходит только зашифрованный файл.</p><details class="details custom-block"><summary>Под капотом</summary><p>Шифрование AES-GCM, ключ выводится из пароля через PBKDF2 в 600 тысяч итераций и существует только в памяти открытой вкладки. Вкладка закрыта - с устройства взять нечего. В IndexedDB лежит только зашифрованный конверт <code>{ salt, iterations, iv, ciphertext }</code>, всё в base64. Открытого текста на диске нет. Расшифровка происходит только после ввода пароля.</p></details><p>→ <a href="/journal.html">Дневник</a></p><h2 id="тренажер-фортепиано-с-midi-клавиатурои" tabindex="-1">Тренажёр фортепиано с MIDI-клавиатурой <a class="header-anchor" href="#тренажер-фортепиано-с-midi-клавиатурои" aria-label="Permalink to &quot;Тренажёр фортепиано с MIDI-клавиатурой&quot;">​</a></h2><p>Для разучивания пьес нужна мгновенная обратная связь, та нота сыграна или не та. Synthesia делает это давно, но это нативное приложение, которое надо ставить и покупать.</p><p>Здесь достаточно подключить MIDI-клавиатуру по USB, браузер увидит её сам, без программ и драйверов. На экране ноты, приложение в реальном времени сверяет сыгранное с партитурой. Режимов два, повтор такта для разучивания и проигрыш фразы целиком для шлифовки. Свои пьесы можно импортировать в форматах MusicXML, ABC и MIDI.</p><details class="details custom-block"><summary>Под капотом</summary><p>Web MIDI API нативно поддерживается в Chrome и Edge. Ноты рендерит OpenSheetMusicDisplay через MusicXML. MIDI-импорт читает тактовый размер из файла; если размера там нет, приложение спросит его перед разбором. Safari не поддерживает Web MIDI API, Firefox держит его под флагом в настройках.</p></details><p>→ <a href="/piano.html">Piano Teacher</a></p><h2 id="редактор-поз-openpose-для-controlnet" tabindex="-1">Редактор поз OpenPose для ControlNet <a class="header-anchor" href="#редактор-поз-openpose-для-controlnet" aria-label="Permalink to &quot;Редактор поз OpenPose для ControlNet&quot;">​</a></h2><p>В работе со Stable Diffusion ControlNet принимает скелет OpenPose как условие для управления позой персонажа. Обычно скелет готовят в AUTOMATIC1111 или ComfyUI, а это локальные Python-инструменты с отдельной установкой. Онлайн-редакторы на Hugging Face работают через их серверы, изображения туда уходят.</p><p>Здесь всё проще. Загружаете фото, хоть пачкой, и скелет распознаётся прямо в браузере, до двух человек на кадре. Точки поправляются мышью, людей можно добавлять и убирать. На выходе PNG с чёрным фоном для ControlNet и JSON в формате OpenPose. Фотографии при этом никуда не отправляются.</p><details class="details custom-block"><summary>Под капотом</summary><p>MediaPipe BlazePose работает в браузере как WASM, без серверных вызовов. 33 ключевые точки BlazePose конвертируются в 18 точек COCO OpenPose (шея вычисляется как середина плеч, в BlazePose такой точки нет). JSON соответствует формату OpenPose v1.3 с нормализованными координатами 0-1. Модель весит ~10,8 МБ и загружается при старте с этого же сайта, не с чужого сервера.</p></details><p>→ <a href="/openpose.html">OpenPose Editor</a></p><h2 id="планировщик-задач" tabindex="-1">Планировщик задач <a class="header-anchor" href="#планировщик-задач" aria-label="Permalink to &quot;Планировщик задач&quot;">​</a></h2><p>База обычная. Проекты, задачи, приоритеты, сроки, канбан-доска и список. Шифрование то же, что в дневнике, ключ живёт только в памяти сессии. Приватные заметки к задачам не покидают зашифрованное хранилище никогда.</p><p>Отдельная возможность - совместная работа с AI-агентом. Планировщик кладёт задачи в обычный файл на диске, и агент вроде Claude Code может читать и править их вместе с вами, не зная пароля и не видя приватных заметок.</p><details class="details custom-block"><summary>Под капотом</summary><p>Мост работает через File System Access API (только Chrome и Edge). В выбранную папку пишется plaintext <code>tasks.json</code>, структура данных без заметок. При фокусе окна приложение перечитывает файл и сливает изменения по принципу last-write-wins, побеждает задача с большим <code>updatedAt</code>. Отсутствие задачи в файле не считается удалением, устаревший файл не сотрёт данные.</p></details><p>→ <a href="/planner.html">Планировщик</a></p><h2 id="журнал-решении" tabindex="-1">Журнал решений <a class="header-anchor" href="#журнал-решении" aria-label="Permalink to &quot;Журнал решений&quot;">​</a></h2><p>Самый нишевый из семи. Решение фиксируется в момент принятия. Контекст, варианты, выбор, ожидаемый исход, уверенность в процентах, дата пересмотра. Когда дата наступает, приложение спросит, сбылось или нет. Из накопленных ответов складывается таблица вида &quot;заявлено 70% уверенности, сбылось X%&quot;.</p><p>Смысл не в угадывании, а в обратной связи. Насколько субъективные оценки соответствуют реальности. Уверенность &quot;на 90%&quot; в событиях, которые сбываются в 60% случаев, - полезный факт о собственном мышлении.</p><p>Локальных аналогов практически нет. Существующие инструменты для отслеживания решений - либо тетрадь, либо корпоративные платформы для командных ретроспектив. Приватный зашифрованный журнал с калибровочной статистикой - пустующая ниша.</p><details class="details custom-block"><summary>Под капотом</summary><p>Калибровка считается оценкой Брайера, где 0 - идеальная калибровка, а 0.25 - уровень подбрасывания монетки. Плюс разбивка по корзинам уверенности. Хранение и шифрование те же, что в дневнике и планировщике.</p></details><p>→ <a href="/decision-journal.html">Журнал решений</a></p><h2 id="ar-engine-аудиовизуализатор-на-webgpu" tabindex="-1">AR Engine, аудиовизуализатор на WebGPU <a class="header-anchor" href="#ar-engine-аудиовизуализатор-на-webgpu" aria-label="Permalink to &quot;AR Engine, аудиовизуализатор на WebGPU&quot;">​</a></h2><p>Задача - не просто слышать звук, а видеть его структуру. Где бас, где атака, насколько &quot;яркий&quot; тембр в данный момент.</p><p>Бросаете трек в окно, и музыка превращается в живую графику. Плазма, узоры Хладни, &quot;зрачок&quot;, расширяющийся на каждый удар, и авторежим, который переключает картины в такт. Бас, высокие и атаки двигают разные части картинки независимо.</p><details class="details custom-block"><summary>Под капотом</summary><p>Аудиоанализ написан на C и собран в WASM через Emscripten. FFT, четыре полосы RMS-огибающих (суб, бас, мид, высокие), детектор битов по спектральному потоку, спектральный центроид. JS читает структуру <code>AudioFrame</code> из 13 чисел прямо из WASM-кучи каждый кадр, без сериализации между слоями. Рендеринг построен на compute shaders WebGPU, до 500 тысяч частиц; на слабом железе число автоматически снижается до 300k или 150k. WebGPU начинался как &quot;только Chrome 113+&quot;, за последний год подтянулись Safari 26 и Firefox на Windows; самый предсказуемый вариант всё ещё Chrome.</p></details><p><a href="/ar/" target="_self">→ AR Engine</a> (Chrome 113+, WebGPU) | <a href="/projects/ar-engine.html">Разбор архитектуры</a></p><hr><p>Все семь инструментов сделаны для личного использования, отсюда их форма. Без регистрации, без мультитенантности, без монетизации. Только браузерные API, шифрование на клиенте и данные, которые не уходят с устройства.</p><p>Честности ради, у local-first есть цена. IndexedDB - хранилище браузера, и браузер вправе его почистить. Поэтому в каждом инструменте есть экспорт в файл. Бэкапы - ответственность пользователя, а не чьего-то облака.</p><p>Это инженерный размен. Меньше чужих серверов, больше собственной ответственности.</p>',43)])])}const b=t(s,[["render",i]]);export{h as __pageData,b as default};
